<div class="wp-block-group"><!-- wp:heading {"fontSize":"heading-medium"} -->
<h2 class="wp-block-heading has-heading-medium-font-size">How We Can Help You</h2>
<!-- /wp:heading -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size">As Canada’s leading authentication and legalization experts, we can handle all aspects of the process for you. We first work with you to ensure your documents are prepared correctly. Once confirmed, you send your documents to our Ottawa office and we then manage the rest on your behalf.</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size">Our friendly specialists would be happy to explain the process and answer your questions. Phone us toll-free at&nbsp;<a href="tel:1-888-433-1011">1-888-433-1011</a>&nbsp;or use our <a href="https://idocs.local/get-in-touch/">contact form</a> to send us a quick online enquiry.</p>
<!-- /wp:paragraph --></div>
<!-- /wp:group -->

<!-- wp:group {"metadata":{"name":"Content Column"},"style":{"spacing":{"blockGap":"var:preset|spacing|40"}},"layout":{"type":"constrained"}} -->
