<!-- /wp:heading -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size"><strong>Hours of Operation</strong>:<br>Mon – Tues &amp; Thurs – Fri: 9:30am – 12:30pm (closed Wed)</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph -->
<p><strong>Address</strong>:<br>388 Main Street, Ottawa, Ontario, Canada, K1S 1E3</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph -->
<p><strong>Phone number:</strong>&nbsp;<a href="tel:613-563-0141">613-563-0141</a></p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size"><strong>Website: </strong><a href="https://misiones.cubaminrex.cu/en/canada/embassy-cuba-canada">Embassy of Cuba</a></p>
