<!-- wp:heading -->
<h2 class="wp-block-heading">Document Authentication</h2>
<!-- /wp:heading -->

<!-- wp:paragraph -->
<p>The document authentication process is the first step of the process to have your document officially recognized in another country that is not a signatory to the Hague Apostille Convention.</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph -->
<p><a href="https://idc.local/our-apostille-services/document-authentication-legalization/document-authentication/" type="page" id="34551">Obtain an apostille</a></p>
<!-- /wp:paragraph --></article>
<!-- /wp:group -->

